```javascript
const request = require('request');

module.exports = function (context) {
    let apiKey = 'your_api_key_here';
    let city = 'London';
    let url = `http://api.openweathermap.org/data/2.5/weather?q=${city}&appid=${apiKey}`;

    request(url, { json: true }, (err, res, body) => {
        if (err) {
            context.send(`Error fetching weather data: ${err}`);
        } else if (res.statusCode !== 200) {
            context.send('Failed to fetch weather data');
        } else {
            let temperature = body.main.temp - 273.15; // Convert Kelvin to Celsius
            context.send(`The current temperature in ${city} is ${temperature.toFixed(2)}°C.`);
        }
    });
};
```

This script uses the `request` module to make an HTTP GET request to the OpenWeatherMap API to fetch the current temperature in London. The response is then processed to extract and format the temperature before sending it back to the user. This example demonstrates how to integrate external services into an Engati chatbot using a script node.

